#
# kubevip-delete.sh
# This script deletes the Kube-VIP ConfigMap and associated resources.

INSTALL_LOG="/persist/kubelog/k3s-install.log"
# shellcheck source=pkg/kube/cluster-utils.sh
. /usr/bin/cluster-utils.sh

failed=0
kubectl delete --ignore-not-found -f /etc/kubevip-ds.yaml || failed=1
# kubevip-cm.yaml is generated by kubevip-apply.sh and may not exist on nodes
# that never ran apply (e.g. non-bootstrap nodes); delete from cluster by name.
kubectl delete --ignore-not-found configmap kubevip -n kube-system || failed=1
kubectl delete --ignore-not-found -f /etc/kubevip-sa.yaml || failed=1
if [ "$failed" -eq 0 ]; then
    logmsg "kubevip-delete: Kube-VIP resources successfully removed"
else
    logmsg "kubevip-delete: Error deleting one or more Kube-VIP resources"
    exit 1
fi
